## Step 5: Concrete generated output example

Given this Prisma schema:

```prisma
datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

generator restClient {
  provider = "prisma-rest-api-client-generator"
  output   = "./generated/rest-client"
}

enum Role {
  ADMIN
  USER
}

model User {
  id        Int      @id @default(autoincrement())
  email     String   @unique
  name      String?
  role      Role     @default(USER)
  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt
  posts     Post[]
}

model Post {
  id        Int     @id @default(autoincrement())
  title     String
  published Boolean @default(false)
  authorId  Int
  author    User    @relation(fields: [authorId], references: [id])
}
```

### Generated `types.ts`

```typescript
export type Role = 'ADMIN' | 'USER'

export interface User {
  id: number
  email: string
  name: string | null
  role: Role
  createdAt: Date
  updatedAt: Date
  posts: Post[] | null
}

export type UserCreateInput = {
  email: string
  name?: string | null
  role?: Role
}

export type UserUpdateInput = {
  email?: string
  name?: string | null
  role?: Role
}

export interface Post {
  id: number
  title: string
  published: boolean
  authorId: number
  author: User | null
}

export type PostCreateInput = {
  title: string
  published?: boolean
  authorId: number
}

export type PostUpdateInput = {
  title?: string
  published?: boolean
  authorId?: number
}
```

Explanation of field decisions for `User`:
- `id`: excluded from inputs (isId=true)
- `email`: required in CreateInput (isRequired=true, hasDefaultValue=false), optional in UpdateInput
- `name`: optional in both (isRequired=false)
- `role`: optional in CreateInput (has @default), optional in UpdateInput
- `createdAt`: excluded (isReadOnly=true in DMMF for @default(now()) scalar fields — actually this depends on Prisma version; if `isReadOnly=false`, it would appear in inputs. The `hasDefaultValue=true` keeps it optional)
- `updatedAt`: excluded (isUpdatedAt=true)
- `posts`: excluded from inputs (kind='object')

For `Post`:
- `id`: excluded from inputs (isId=true)
- `author`: excluded from inputs (kind='object'), but present in interface
- `authorId`: included in inputs (it's a scalar FK — `isReadOnly=true` is set on FK fields in some Prisma versions; need to verify)

**Note on `authorId` and `isReadOnly`:** In current Prisma DMMF, foreign key scalar fields (`authorId`) have `isReadOnly: true` because they are managed via the relation. This would cause `isCreateInputField` to exclude them. This is actually correct REST API behavior — you'd typically set the relation via the object or by posting to a nested route. However, if you want `authorId` in the input, you can modify `isCreateInputField` to not exclude `isReadOnly` fields that are not `@id`. The plan's current logic excludes them to match Prisma's own `CreateInput` semantics. This is documented as a decision point implementers should be aware of.

### Generated `rest-api-client.ts`

```typescript
export class UserClient {
  constructor(private readonly baseUrl: string) {}

  async findMany(): Promise<User[]> {
    const res = await fetch(`${this.baseUrl}/users`)
    if (!res.ok) throw new Error(`findMany User failed: ${res.status}`)
    return res.json() as Promise<User[]>
  }

  async findUnique(id: number): Promise<User | null> {
    const res = await fetch(`${this.baseUrl}/users/${id}`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(`findUnique User failed: ${res.status}`)
    return res.json() as Promise<User>
  }

  async create(data: UserCreateInput): Promise<User> {
    const res = await fetch(`${this.baseUrl}/users`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(`create User failed: ${res.status}`)
    return res.json() as Promise<User>
  }

  async update(id: number, data: UserUpdateInput): Promise<User> {
    const res = await fetch(`${this.baseUrl}/users/${id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(`update User failed: ${res.status}`)
    return res.json() as Promise<User>
  }

  async delete(id: number): Promise<void> {
    const res = await fetch(`${this.baseUrl}/users/${id}`, { method: 'DELETE' })
    if (!res.ok) throw new Error(`delete User failed: ${res.status}`)
  }
}

export class PostClient {
  constructor(private readonly baseUrl: string) {}
  // ... same pattern with /posts URL segment and number id type
}

export class RestApiClient {
  readonly user: UserClient
  readonly post: PostClient

  constructor(baseUrl: string) {
    this.user = new UserClient(baseUrl)
    this.post = new PostClient(baseUrl)
  }
}
```

