pnpm-debug.log
dist/
*.tsbuildinfo
```

---

### 2. `src/field-type-mapper.ts`

Pure mapping function, no side effects. Maps a `DMMF.Field` → TypeScript type string, handling `isList` wrapping for all field kinds.

```typescript
import type * as DMMF from '@prisma/dmmf'

/** Maps a DMMF field to its TypeScript type string, including list wrapping. */
export function mapFieldToTsType(field: DMMF.Field): string {
  const base = resolveBaseType(field)
  return field.isList ? `${base}[]` : base
}

function resolveBaseType(field: DMMF.Field): string {
  if (field.kind === 'object' || field.kind === 'enum') return field.type
  if (field.kind === 'unsupported') return 'unknown'
  return mapScalarType(field.type)
}

function mapScalarType(type: string): string {
  switch (type) {
    case 'String':   return 'string'
    case 'Int':
    case 'Float':
    case 'Decimal':  return 'number'
    case 'Boolean':  return 'boolean'
    case 'DateTime': return 'Date'
    case 'Json':     return 'Record<string, unknown>'
    case 'BigInt':   return 'bigint'
    case 'Bytes':    return 'Uint8Array'
    default:         return 'unknown'
  }
}
```

---

### 3. `src/types-file.ts`

Generates full `types.ts` content using template-literal string building.

**Enum → TypeScript union type** (avoids the enum keyword's value/type duality):
```typescript
// 'ADMIN' | 'USER'
export type Role = 'ADMIN' | 'USER'
```

**Field inclusion rules for `CreateInput`/`UpdateInput`** — exclude if any of:
- `field.isId`
- `field.isReadOnly` (covers FK scalars like `authorId`, which Prisma marks read-only)
- `field.isGenerated === true`
- `field.isUpdatedAt === true`
- `field.kind === 'object'`

**`CreateInput` requiredness**: a field is required if `isRequired && !hasDefaultValue`.  
**`UpdateInput`**: all fields optional (Partial).

**Non-required fields get `| null`** to match Prisma's own generated type semantics.

```typescript
import type * as DMMF from '@prisma/dmmf'
import { mapFieldToTsType } from './field-type-mapper'

export function generateTypesFileContent(dmmf: DMMF.Document): string {
  const sections: string[] = []

  for (const enumDef of dmmf.datamodel.enums) {
    sections.push(generateEnum(enumDef))
  }
  for (const model of dmmf.datamodel.models) {
    sections.push(generateInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
  }

  return sections.join('\n\n') + '\n'
}

function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}`
}

function generateInterface(model: DMMF.Model): string {
  const lines = model.fields.map((f) => {
    const tsType = mapFieldToTsType(f)
    const nullable = !f.isRequired ? ' | null' : ''
    return `  ${f.name}: ${tsType}${nullable}`
  })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields.filter(isInputField)
  const lines = fields.map((f) => {
    const tsType = mapFieldToTsType(f)
    const required = f.isRequired && !f.hasDefaultValue
    const opt = required ? '' : '?'
    const nullable = !f.isRequired ? ' | null' : ''
    return `  ${f.name}${opt}: ${tsType}${nullable}`
  })
  return `export type ${model.name}CreateInput = {\n${lines.join('\n')}\n}`
}

function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields.filter(isInputField)
  const lines = fields.map((f) => {
    const tsType = mapFieldToTsType(f)
    const nullable = !f.isRequired ? ' | null' : ''
    return `  ${f.name}?: ${tsType}${nullable}`
  })
  return `export type ${model.name}UpdateInput = {\n${lines.join('\n')}\n}`
}

function isInputField(f: DMMF.Field): boolean {
  return !f.isId && !f.isReadOnly && f.isGenerated !== true && f.isUpdatedAt !== true && f.kind !== 'object'
}
```

---

### 4. `src/client-file.ts`

Generates `rest-api-client.ts`. Uses `dmmf.mappings.modelOperations[].plural` for URL segments; detects the `@id` field for the primary-key TypeScript type.

```typescript
