    return res.json() as Promise<${n}[]>
  }

  async findUnique(id: ${idType}): Promise<${n} | null> {
    const res = await fetch(\`\${this.baseUrl}/${segment}/\${id}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`findUnique ${n} failed: \${res.status}\`)
    return res.json() as Promise<${n}>
  }

  async create(data: ${n}CreateInput): Promise<${n}> {
    const res = await fetch(\`\${this.baseUrl}/${segment}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`create ${n} failed: \${res.status}\`)
    return res.json() as Promise<${n}>
  }

  async update(id: ${idType}, data: ${n}UpdateInput): Promise<${n}> {
    const res = await fetch(\`\${this.baseUrl}/${segment}/\${id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`update ${n} failed: \${res.status}\`)
    return res.json() as Promise<${n}>
  }

  async delete(id: ${idType}): Promise<void> {
    const res = await fetch(\`\${this.baseUrl}/${segment}/\${id}\`, { method: 'DELETE' })
    if (!res.ok) throw new Error(\`delete ${n} failed: \${res.status}\`)
  }
}`
}

function generateTopLevelClient(models: readonly DMMF.Model[]): string {
  const props = models.map((m) => `  readonly ${lcFirst(m.name)}: ${m.name}Client`).join('\n')
  const inits = models.map((m) => `    this.${lcFirst(m.name)} = new ${m.name}Client(baseUrl)`).join('\n')
  return `export class RestApiClient {\n${props}\n\n  constructor(baseUrl: string) {\n${inits}\n  }\n}`
}

function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}
```

> Uses native `fetch` (available Node ≥18; the repo requires Node ^20.19). `as Promise<T>` is necessary because `Response.json()` returns `Promise<any>`.  
> Uses `PATCH` for `update` (matches the fully-optional `UpdateInput` semantics).

