### 1. Package boilerplate

**`package.json`** — mirrors `@prisma/debug` plus `bin` (required for Prisma to spawn it as a process) and workspace dependencies:

```json
{
  "name": "@prisma/rest-api-client-generator",
  "version": "0.0.0",
  "description": "Prisma generator that produces a typed TypeScript REST API client",
  "main": "dist/index.js",
  "module": "dist/index.mjs",
  "types": "dist/index.d.ts",
  "exports": {
    ".": {
      "require": { "types": "./dist/index.d.ts", "default": "./dist/index.js" },
      "import": { "types": "./dist/index.d.mts", "default": "./dist/index.mjs" }
    }
  },
  "bin": {
    "prisma-rest-api-client-generator": "dist/index.js"
  },
  "license": "Apache-2.0",
  "repository": {
    "type": "git",
    "url": "https://github.com/prisma/prisma.git",
    "directory": "packages/rest-api-client-generator"
  },
  "homepage": "https://www.prisma.io",
  "bugs": "https://github.com/prisma/prisma/issues",
  "dependencies": {
    "@prisma/dmmf": "workspace:*",
    "@prisma/generator": "workspace:*",
    "@prisma/generator-helper": "workspace:*"
  },
  "devDependencies": {
    "@types/node": "~20.19.24",
    "typescript": "5.4.5"
  },
  "scripts": {
    "dev": "DEV=true tsx helpers/build.ts",
    "build": "tsx helpers/build.ts",
    "test": "vitest run",
    "prepublishOnly": "pnpm run build"
  },
  "files": ["README.md", "dist"],
  "sideEffects": false
}
```

> Listing the workspace packages as `dependencies` (not `devDependencies`) marks them as externals during the esbuild bundle step — `helpers/compile/build.ts` treats `dependencies` as external.

**`tsconfig.json`:**
```json
{ "extends": "../../tsconfig.json", "include": ["./**/*"] }
```

**`tsconfig.build.json`:**
```json
{
  "extends": "../../tsconfig.build.regular.json",
  "compilerOptions": { "outDir": "dist" },
  "include": ["src"]
}
```

**`helpers/build.ts`** — identical to `packages/debug/helpers/build.ts`:
```typescript
import { build } from '../../../helpers/compile/build'
import { adapterConfig } from '../../../helpers/compile/configs'

void build(adapterConfig)
```

**`.gitignore`:**
```
node_modules
.DS_Store
yarn-error.log
pnpm-debug.log
dist/
*.tsbuildinfo
```

---

### 2. `src/field-type-mapper.ts`

Pure mapping function, no side effects. Maps a `DMMF.Field` → TypeScript type string, handling `isList` wrapping for all field kinds.

```typescript
import type * as DMMF from '@prisma/dmmf'

/** Maps a DMMF field to its TypeScript type string, including list wrapping. */
export function mapFieldToTsType(field: DMMF.Field): string {
  const base = resolveBaseType(field)
  return field.isList ? `${base}[]` : base
}

function resolveBaseType(field: DMMF.Field): string {
  if (field.kind === 'object' || field.kind === 'enum') return field.type
  if (field.kind === 'unsupported') return 'unknown'
  return mapScalarType(field.type)
}

function mapScalarType(type: string): string {
  switch (type) {
    case 'String':   return 'string'
    case 'Int':
    case 'Float':
    case 'Decimal':  return 'number'
    case 'Boolean':  return 'boolean'
    case 'DateTime': return 'Date'
    case 'Json':     return 'Record<string, unknown>'
    case 'BigInt':   return 'bigint'
    case 'Bytes':    return 'Uint8Array'
    default:         return 'unknown'
  }
}
```

---

### 3. `src/types-file.ts`

Generates full `types.ts` content using template-literal string building.

**Enum → TypeScript union type** (avoids the enum keyword's value/type duality):
```typescript
// 'ADMIN' | 'USER'
export type Role = 'ADMIN' | 'USER'
```

**Field inclusion rules for `CreateInput`/`UpdateInput`** — exclude if any of:
- `field.isId`
- `field.isReadOnly` (covers FK scalars like `authorId`, which Prisma marks read-only)
- `field.isGenerated === true`
- `field.isUpdatedAt === true`
- `field.kind === 'object'`

**`CreateInput` requiredness**: a field is required if `isRequired && !hasDefaultValue`.  
**`UpdateInput`**: all fields optional (Partial).

**Non-required fields get `| null`** to match Prisma's own generated type semantics.

```typescript
import type * as DMMF from '@prisma/dmmf'
import { mapFieldToTsType } from './field-type-mapper'

export function generateTypesFileContent(dmmf: DMMF.Document): string {
  const sections: string[] = []

  for (const enumDef of dmmf.datamodel.enums) {
    sections.push(generateEnum(enumDef))
  }
  for (const model of dmmf.datamodel.models) {
    sections.push(generateInterface(model))
    sections.push(generateCreateInput(model))
    sections.push(generateUpdateInput(model))
  }

  return sections.join('\n\n') + '\n'
}

function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${enumDef.name} = ${values}`
}

function generateInterface(model: DMMF.Model): string {
  const lines = model.fields.map((f) => {
    const tsType = mapFieldToTsType(f)
    const nullable = !f.isRequired ? ' | null' : ''
    return `  ${f.name}: ${tsType}${nullable}`
  })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

function generateCreateInput(model: DMMF.Model): string {
  const fields = model.fields.filter(isInputField)
  const lines = fields.map((f) => {
    const tsType = mapFieldToTsType(f)
    const required = f.isRequired && !f.hasDefaultValue
    const opt = required ? '' : '?'
    const nullable = !f.isRequired ? ' | null' : ''
    return `  ${f.name}${opt}: ${tsType}${nullable}`
  })
  return `export type ${model.name}CreateInput = {\n${lines.join('\n')}\n}`
}

function generateUpdateInput(model: DMMF.Model): string {
  const fields = model.fields.filter(isInputField)
  const lines = fields.map((f) => {
    const tsType = mapFieldToTsType(f)
    const nullable = !f.isRequired ? ' | null' : ''
    return `  ${f.name}?: ${tsType}${nullable}`
  })
  return `export type ${model.name}UpdateInput = {\n${lines.join('\n')}\n}`
}

function isInputField(f: DMMF.Field): boolean {
  return !f.isId && !f.isReadOnly && f.isGenerated !== true && f.isUpdatedAt !== true && f.kind !== 'object'
}
```

---

### 4. `src/client-file.ts`

Generates `rest-api-client.ts`. Uses `dmmf.mappings.modelOperations[].plural` for URL segments; detects the `@id` field for the primary-key TypeScript type.

```typescript
import type * as DMMF from '@prisma/dmmf'
import { mapFieldToTsType } from './field-type-mapper'

export function generateClientFileContent(dmmf: DMMF.Document): string {
  const sections: string[] = []
  for (const model of dmmf.datamodel.models) {
    const segment = resolveSegment(model.name, dmmf)
    const idType  = resolveIdType(model)
    sections.push(generateModelClient(model, segment, idType))
  }
  sections.push(generateTopLevelClient(dmmf.datamodel.models))
  return sections.join('\n\n') + '\n'
}

function resolveSegment(modelName: string, dmmf: DMMF.Document): string {
  return dmmf.mappings.modelOperations.find((m) => m.model === modelName)?.plural
    ?? modelName.toLowerCase() + 's'
}

function resolveIdType(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  return idField ? mapFieldToTsType(idField) : 'number | string'
}

function generateModelClient(model: DMMF.Model, segment: string, idType: string): string {
  const n = model.name
  return `export class ${n}Client {
  constructor(private readonly baseUrl: string) {}

  async findMany(): Promise<${n}[]> {
    const res = await fetch(\`\${this.baseUrl}/${segment}\`)
    if (!res.ok) throw new Error(\`findMany ${n} failed: \${res.status}\`)
    return res.json() as Promise<${n}[]>
  }

  async findUnique(id: ${idType}): Promise<${n} | null> {
    const res = await fetch(\`\${this.baseUrl}/${segment}/\${id}\`)
    if (res.status === 404) return null
    if (!res.ok) throw new Error(\`findUnique ${n} failed: \${res.status}\`)
    return res.json() as Promise<${n}>
  }

  async create(data: ${n}CreateInput): Promise<${n}> {
    const res = await fetch(\`\${this.baseUrl}/${segment}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`create ${n} failed: \${res.status}\`)
    return res.json() as Promise<${n}>
  }

  async update(id: ${idType}, data: ${n}UpdateInput): Promise<${n}> {
    const res = await fetch(\`\${this.baseUrl}/${segment}/\${id}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(data),
    })
    if (!res.ok) throw new Error(\`update ${n} failed: \${res.status}\`)
    return res.json() as Promise<${n}>
  }

  async delete(id: ${idType}): Promise<void> {
    const res = await fetch(\`\${this.baseUrl}/${segment}/\${id}\`, { method: 'DELETE' })
    if (!res.ok) throw new Error(\`delete ${n} failed: \${res.status}\`)
  }
}`
}

function generateTopLevelClient(models: readonly DMMF.Model[]): string {
  const props = models.map((m) => `  readonly ${lcFirst(m.name)}: ${m.name}Client`).join('\n')
  const inits = models.map((m) => `    this.${lcFirst(m.name)} = new ${m.name}Client(baseUrl)`).join('\n')
  return `export class RestApiClient {\n${props}\n\n  constructor(baseUrl: string) {\n${inits}\n  }\n}`
}

function lcFirst(s: string): string {
  return s.charAt(0).toLowerCase() + s.slice(1)
}
```

> Uses native `fetch` (available Node ≥18; the repo requires Node ^20.19). `as Promise<T>` is necessary because `Response.json()` returns `Promise<any>`.  
> Uses `PATCH` for `update` (matches the fully-optional `UpdateInput` semantics).

---

### 5. `src/generate-client.ts`

```typescript
import fs from 'node:fs/promises'
import path from 'node:path'
import type { GeneratorOptions } from '@prisma/generator'
import { generateClientFileContent } from './client-file'
import { generateTypesFileContent } from './types-file'

export async function generateRestApiClient(options: GeneratorOptions): Promise<void> {
  const outputDir = resolveOutputDir(options)
  await fs.mkdir(outputDir, { recursive: true })

  const typesContent  = generateTypesFileContent(options.dmmf)
  const clientContent = generateClientFileContent(options.dmmf)
  const indexContent  = `export * from './types'\nexport * from './rest-api-client'\n`

  await Promise.all([
    fs.writeFile(path.join(outputDir, 'types.ts'), typesContent, 'utf-8'),
    fs.writeFile(path.join(outputDir, 'rest-api-client.ts'), clientContent, 'utf-8'),
    fs.writeFile(path.join(outputDir, 'index.ts'), indexContent, 'utf-8'),
  ])
}

function resolveOutputDir(options: GeneratorOptions): string {
  const value = options.generator.output?.value
  if (value) return value
  return path.join(path.dirname(options.schemaPath), 'generated', 'rest-client')
}
```

---

### 6. `src/index.ts`

The `#!/usr/bin/env node` shebang **must be the very first line** — esbuild preserves it only when it is the first byte of the entry point.

```typescript
#!/usr/bin/env node

import { generatorHandler } from '@prisma/generator-helper'
import type { GeneratorConfig, GeneratorManifest, GeneratorOptions } from '@prisma/generator'
import { generateRestApiClient } from './generate-client'

generatorHandler({
  onManifest(_config: GeneratorConfig): GeneratorManifest {
    return {
      prettyName: 'Prisma REST API Client Generator',
      defaultOutput: './generated/rest-client',
      version: '0.0.0',
    }
  },
  async onGenerate(options: GeneratorOptions): Promise<void> {
    await generateRestApiClient(options)
  },
})
```

---

### 7. Unit tests (`src/__tests__/`)

All three test files call pure string-generating functions directly — no `fs` mocking needed.

**`field-type-mapper.test.ts`** — one test per scalar type, plus `object`, `enum`, `unsupported`, and `isList` wrapping. Uses a small `field()` helper to build minimal `DMMF.Field` stubs.

**`types-file.test.ts`** — constructs a minimal `DMMF.Document` with one enum (`Role`), one model (`User` with id/email/name/role/posts fields). Asserts with `toContain`:
- Enum union generated correctly
- Interface contains all fields with correct nullability
- `CreateInput` excludes `id` and `posts`, makes `email` required, `name`/`role` optional
- `UpdateInput` makes all fields optional

**`client-file.test.ts`** — same minimal `DMMF.Document` with `mappings.modelOperations = [{ model: 'User', plural: 'users' }]`. Asserts:
- `UserClient` class emitted
- URL uses `users` (from `plural`)
- Each method has the correct signature
- `RestApiClient` has `readonly user: UserClient`
- Fallback URL segment when mapping missing (`users` from `'User'.toLowerCase() + 's'`)
- Fallback id type (`number | string`) when no `@id` field

---

### 8. Root-level modifications

**`tsconfig.build.bundle.json`** — add inside `compilerOptions.paths` (after `@prisma/generator-helper`):
```json
"@prisma/rest-api-client-generator": ["./packages/rest-api-client-generator/src"]
```

**`.github/workflows/test-template.yml`** — insert after the `generator` step (currently ending at line 862):
```yaml
      - run: pnpm run test
        name: 'rest-api-client-generator'
        working-directory: packages/rest-api-client-generator
```

---

## Concrete example output

Schema with `Role` enum, `User` model, `Post` model:

**`types.ts` (excerpt):**
```typescript
export type Role = 'ADMIN' | 'USER'

export interface User {
  id: number
  email: string
  name: string | null
  role: Role
  createdAt: Date
  updatedAt: Date
  posts: Post[] | null
}

export type UserCreateInput = {
  email: string
  name?: string | null
  role?: Role
}

export type UserUpdateInput = {
  email?: string
  name?: string | null
  role?: Role
}
```
> `createdAt` appears in the interface (it's readable) but is absent from `CreateInput`/`UpdateInput` because `hasDefaultValue: true` in DMMF for `@default(now())` makes it optional and Prisma's DMMF sets `isReadOnly: true` on `@default` scalar fields managed by the DB.  
> `updatedAt` excluded because `isUpdatedAt: true`.  
> `posts` excluded from inputs because `kind === 'object'`.

**`rest-api-client.ts` (excerpt):**
```typescript
export class UserClient {
  constructor(private readonly baseUrl: string) {}
  async findMany(): Promise<User[]> { ... fetch(`${this.baseUrl}/users`) }
  async findUnique(id: number): Promise<User | null> { ... }
  async create(data: UserCreateInput): Promise<User> { ... }
  async update(id: number, data: UserUpdateInput): Promise<User> { ... }
  async delete(id: number): Promise<void> { ... }
}

export class RestApiClient {
  readonly user: UserClient
  readonly post: PostClient
  constructor(baseUrl: string) {
    this.user = new UserClient(baseUrl)
    this.post = new PostClient(baseUrl)
  }
}
```

---

## Verification

1. **Build**: `pnpm --filter @prisma/rest-api-client-generator build`  
   → Verify `dist/index.js` exists and starts with `#!/usr/bin/env node`.

2. **Unit tests**: `pnpm --filter @prisma/rest-api-client-generator test`  
   → All assertions pass with no file I/O.

3. **End-to-end** — create `sandbox/rest-client-test/schema.prisma` with:
   ```prisma
   generator restClient {
     provider = "node ../../packages/rest-api-client-generator/dist/index.js"
     output   = "./generated/rest-client"
   }
   ```
   Run: `pnpm dlx prisma generate --schema=sandbox/rest-client-test/schema.prisma`  
   → Verify `generated/rest-client/types.ts`, `rest-api-client.ts`, `index.ts` exist.

4. **Type-check generated output**: create a consumer file importing from `./generated/rest-client` and run `tsc --noEmit` — must compile cleanly.

---

## Key design decisions

| Decision | Rationale |
|---|---|
| Union types (`'A' \| 'B'`) for enums | Avoids TypeScript enum value/type duality; matches Prisma Client's own output |
| `isReadOnly` excludes FK scalars from inputs | Prisma marks FK scalars (`authorId`) `isReadOnly: true`; excluding them matches Prisma's own `CreateInput` semantics |
| Native `fetch` in generated client | Node ≥18 built-in; no extra dependency; repo targets Node ^20.19 |
| `PATCH` for `update` | Idiomatic for partial updates (all `UpdateInput` fields are optional) |
| Template strings (not `@prisma/ts-builders`) | The output is simple, linear text; AST builders add indirection without benefit at this scope |
| `adapterConfig` build | Single-entry bundled output is correct for an executable generator (vs a library) |

