import type { DMMF } from '@prisma/generator-helper'

/**
 * Maps a Prisma scalar type name to the corresponding TypeScript primitive type.
 * Returns `'unknown'` for unrecognised scalars so generated code still compiles.
 */
export function scalarToTsType(scalarType: string): string {
  switch (scalarType) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      // Serialised as ISO-8601 strings over HTTP.
      return 'string'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      // Serialised as base-64 strings over HTTP.
      return 'string'
    case 'Decimal':
      // Serialised as decimal strings to avoid floating-point loss.
      return 'string'
    default:
      return 'unknown'
  }
}

/**
 * Returns the base TypeScript type for a DMMF field (no list or nullability
 * modifiers applied yet).
 */
export function fieldBaseType(field: DMMF.Field): string {
  switch (field.kind) {
    case 'scalar':
      return scalarToTsType(field.type)
    case 'enum':
      return field.type
    case 'object':
      return field.type
    case 'unsupported':
      return 'unknown'
    default:
      return 'unknown'
  }
}

/**
 * Returns the full TypeScript type string for a DMMF model field as it
 * appears in the generated model interface, including list and nullability
 * modifiers.
 */
export function fieldToTsType(field: DMMF.Field): string {
  const base = fieldBaseType(field)
  const withList = field.isList ? `${base}[]` : base
  return field.isRequired ? withList : `${withList} | null`
}

