import type { DMMF } from '@prisma/generator-helper'

import { fieldBaseType, fieldToTsType } from './field-type-mapper'

/**
 * Generates the content of the `types.ts` output file.
 *
 * The file contains:
 * - One union type per Prisma enum
 * - One interface per model (all scalar/enum fields + optional relation fields)
 * - `<Model>CreateInput` — writable fields, required unless the field has a
 *   default value or is optional in the schema
 * - `<Model>UpdateInput` — same writable fields, all optional (PATCH semantics)
 * - `<Model>WhereUniqueInput` — `@id` fields only
 */
export function generateTypesFile(dmmf: DMMF.Document): string {
  const lines: string[] = []

  for (const enumDef of dmmf.datamodel.enums) {
    const values = enumDef.values.map((v) => `'${v.name}'`).join(' | ')
    lines.push(`export type ${enumDef.name} = ${values}`)
    lines.push('')
  }

  for (const model of dmmf.datamodel.models) {
    lines.push(...modelInterface(model))
    lines.push(...createInputInterface(model))
    lines.push(...updateInputInterface(model))
    lines.push(...whereUniqueInputInterface(model))
  }

  return lines.join('\n')
}

function modelInterface(model: DMMF.Model): string[] {
  const lines: string[] = []
  lines.push(`export interface ${model.name} {`)
  for (const field of model.fields) {
    if (field.kind === 'unsupported') continue
    if (field.kind === 'object') {
      // Relation fields may or may not be included in a REST response, so they
      // are typed as optional regardless of schema requiredness.
      const base = fieldBaseType(field)
      const type = field.isList ? `${base}[]` : `${base} | null`
      lines.push(`  ${field.name}?: ${type}`)
    } else {
      lines.push(`  ${field.name}: ${fieldToTsType(field)}`)
    }
  }
  lines.push('}')
  lines.push('')
  return lines
}

function writableScalarEnumFields(model: DMMF.Model): readonly DMMF.Field[] {
  // isReadOnly is true for FK scalars (e.g. `authorId`), which Prisma manages
  // internally and which callers should not set directly.
  return model.fields.filter((f) => (f.kind === 'scalar' || f.kind === 'enum') && !f.isReadOnly)
}

function createInputInterface(model: DMMF.Model): string[] {
  const lines: string[] = []
  lines.push(`export interface ${model.name}CreateInput {`)
  for (const field of writableScalarEnumFields(model)) {
    const base = fieldBaseType(field)
    const type = field.isList ? `${base}[]` : base
    // Fields with a database default or that are schema-optional may be omitted
    // by the caller; the server will supply the value.
    const optional = !field.isRequired || field.hasDefaultValue ? '?' : ''
    lines.push(`  ${field.name}${optional}: ${type}`)
  }
  lines.push('}')
  lines.push('')
  return lines
}

function updateInputInterface(model: DMMF.Model): string[] {
  const lines: string[] = []
  lines.push(`export interface ${model.name}UpdateInput {`)
  for (const field of writableScalarEnumFields(model)) {
    const base = fieldBaseType(field)
    const type = field.isList ? `${base}[]` : base
    lines.push(`  ${field.name}?: ${type}`)
  }
  lines.push('}')
  lines.push('')
  return lines
}

function whereUniqueInputInterface(model: DMMF.Model): string[] {
  const lines: string[] = []
  lines.push(`export interface ${model.name}WhereUniqueInput {`)
  for (const field of model.fields.filter((f) => f.isId)) {
    const base = fieldBaseType(field)
    const type = field.isList ? `${base}[]` : base
    lines.push(`  ${field.name}: ${type}`)
  }
  lines.push('}')
  lines.push('')
  return lines
}

