import type { DMMF } from '@prisma/generator-helper'

/**
 * Generates the content of the `rest-api-client.ts` output file.
 *
 * For every Prisma model the file contains a `<Model>Client` class with five
 * CRUD methods that call a REST API via the native `fetch` API:
 *
 * - `findMany`   — GET  /<model>
 * - `findUnique` — GET  /<model>/:id  (returns `null` on 404)
 * - `create`     — POST /<model>
 * - `update`     — PATCH /<model>/:id
 * - `delete`     — DELETE /<model>/:id
 *
 * A top-level `RestApiClient` class aggregates all per-model clients as
 * camelCase properties (e.g. `client.blogPost`).
 */
export function generateClientFile(dmmf: DMMF.Document): string {
  const lines: string[] = []

  lines.push(...importsBlock(dmmf))

  for (const model of dmmf.datamodel.models) {
    lines.push(...modelClientClass(model))
  }

  lines.push(...aggregateClientClass(dmmf))

  return lines.join('\n')
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function importsBlock(dmmf: DMMF.Document): string[] {
  const typeNames = dmmf.datamodel.models.flatMap((m) => [
    m.name,
    `${m.name}CreateInput`,
    `${m.name}UpdateInput`,
    `${m.name}WhereUniqueInput`,
  ])

  return [
    `import type {`,
    ...typeNames.map((t) => `  ${t},`),
    `} from './types'`,
    ``,
  ]
}

function idPath(model: DMMF.Model): string {
  // Builds the URL path segment from the @id fields, e.g. `${where.id}` or
  // `${where.tenantId}/${where.userId}` for composite keys.
  const idFields = model.fields.filter((f) => f.isId)
  if (idFields.length === 0) return '${JSON.stringify(where)}'
  return idFields.map((f) => `\${where.${f.name}}`).join('/')
}

function modelClientClass(model: DMMF.Model): string[] {
  const name = model.name
  const slug = name.toLowerCase()
  const id = idPath(model)
  const lines: string[] = []

  lines.push(`export class ${name}Client {`)
  lines.push(`  #baseUrl: string`)
  lines.push(``)
  lines.push(`  constructor(baseUrl: string) {`)
  lines.push(`    this.#baseUrl = baseUrl.replace(/\\/$/, '')`)
  lines.push(`  }`)
  lines.push(``)

  // findMany
  lines.push(`  async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {`)
  lines.push(`    const search = params`)
  lines.push(
    `      ? '?' + new URLSearchParams(Object.entries(params).map(([k, v]) => [k, String(v)])).toString()`,
  )
  lines.push(`      : ''`)
  lines.push(`    const response = await fetch(\`\${this.#baseUrl}/${slug}\${search}\`)`)
  lines.push(`    return response.json() as Promise<${name}[]>`)
  lines.push(`  }`)
  lines.push(``)

  // findUnique
  lines.push(`  async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {`)
  lines.push(`    const response = await fetch(\`\${this.#baseUrl}/${slug}/${id}\`)`)
  lines.push(`    if (response.status === 404) return null`)
  lines.push(`    return response.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push(``)

  // create
  lines.push(`  async create(data: ${name}CreateInput): Promise<${name}> {`)
  lines.push(`    const response = await fetch(\`\${this.#baseUrl}/${slug}\`, {`)
  lines.push(`      method: 'POST',`)
  lines.push(`      headers: { 'Content-Type': 'application/json' },`)
  lines.push(`      body: JSON.stringify(data),`)
  lines.push(`    })`)
  lines.push(`    return response.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push(``)

  // update
  lines.push(`  async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {`)
  lines.push(`    const response = await fetch(\`\${this.#baseUrl}/${slug}/${id}\`, {`)
  lines.push(`      method: 'PATCH',`)
  lines.push(`      headers: { 'Content-Type': 'application/json' },`)
  lines.push(`      body: JSON.stringify(data),`)
  lines.push(`    })`)
  lines.push(`    return response.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push(``)

  // delete
  lines.push(`  async delete(where: ${name}WhereUniqueInput): Promise<${name}> {`)
  lines.push(`    const response = await fetch(\`\${this.#baseUrl}/${slug}/${id}\`, {`)
  lines.push(`      method: 'DELETE',`)
  lines.push(`    })`)
  lines.push(`    return response.json() as Promise<${name}>`)
  lines.push(`  }`)
  lines.push(`}`)
  lines.push(``)

  return lines
}

function aggregateClientClass(dmmf: DMMF.Document): string[] {
  const lines: string[] = []
  lines.push(`export class RestApiClient {`)

  for (const model of dmmf.datamodel.models) {
    const prop = toCamelCase(model.name)
    lines.push(`  readonly ${prop}: ${model.name}Client`)
  }

  lines.push(``)
  lines.push(`  constructor(baseUrl: string) {`)
  for (const model of dmmf.datamodel.models) {
    const prop = toCamelCase(model.name)
    lines.push(`    this.${prop} = new ${model.name}Client(baseUrl)`)
  }
  lines.push(`  }`)
  lines.push(`}`)
  lines.push(``)

  return lines
}

function toCamelCase(pascalName: string): string {
  return pascalName.charAt(0).toLowerCase() + pascalName.slice(1)
}

