import { describe, expect, test } from 'vitest'

import { fieldBaseType, fieldToTsType, scalarToTsType } from '../field-type-mapper'
import type { DMMF } from '@prisma/generator-helper'

describe('scalarToTsType', () => {
  test.each([
    ['String', 'string'],
    ['Boolean', 'boolean'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['BigInt', 'bigint'],
    ['DateTime', 'string'],
    ['Json', 'unknown'],
    ['Bytes', 'string'],
    ['Decimal', 'string'],
    ['SomeFuturePrismaType', 'unknown'],
  ])('%s → %s', (scalar, expected) => {
    expect(scalarToTsType(scalar)).toBe(expected)
  })
})

describe('fieldBaseType', () => {
  const makeField = (overrides: Partial<DMMF.Field>): DMMF.Field => ({
    kind: 'scalar',
    name: 'f',
    type: 'String',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  })

  test('scalar field maps through scalarToTsType', () => {
    expect(fieldBaseType(makeField({ kind: 'scalar', type: 'Int' }))).toBe('number')
  })

  test('enum field returns the enum name as-is', () => {
    expect(fieldBaseType(makeField({ kind: 'enum', type: 'Role' }))).toBe('Role')
  })

  test('object (relation) field returns the model name as-is', () => {
    expect(fieldBaseType(makeField({ kind: 'object', type: 'Post' }))).toBe('Post')
  })

  test('unsupported field returns unknown', () => {
    expect(fieldBaseType(makeField({ kind: 'unsupported', type: 'circle' }))).toBe('unknown')
  })
})

describe('fieldToTsType', () => {
  const makeField = (overrides: Partial<DMMF.Field>): DMMF.Field => ({
    kind: 'scalar',
    name: 'f',
    type: 'String',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  })

  test('required scalar produces plain type', () => {
    expect(fieldToTsType(makeField({ type: 'String', isRequired: true }))).toBe('string')
  })

  test('optional scalar appends | null', () => {
    expect(fieldToTsType(makeField({ type: 'String', isRequired: false }))).toBe('string | null')
  })

  test('required list scalar', () => {
    expect(fieldToTsType(makeField({ type: 'String', isRequired: true, isList: true }))).toBe('string[]')
  })

  test('optional list scalar', () => {
    expect(fieldToTsType(makeField({ type: 'String', isRequired: false, isList: true }))).toBe('string[] | null')
  })

  test('required enum', () => {
    expect(fieldToTsType(makeField({ kind: 'enum', type: 'Role', isRequired: true }))).toBe('Role')
  })

  test('optional relation', () => {
    expect(fieldToTsType(makeField({ kind: 'object', type: 'User', isRequired: false }))).toBe('User | null')
  })
})

