import { describe, expect, test } from 'vitest'

import { generateTypesFile } from '../types-file'
import { testDmmf } from './fixtures'

describe('generateTypesFile', () => {
  const output = generateTypesFile(testDmmf)

  test('emits enum as a union type', () => {
    expect(output).toContain("export type Role = 'USER' | 'ADMIN'")
  })

  test('emits model interface with scalar fields', () => {
    expect(output).toContain('export interface User {')
    expect(output).toContain('  id: string')
    expect(output).toContain('  email: string')
    // Optional scalar → | null
    expect(output).toContain('  name: string | null')
    expect(output).toContain('  role: Role')
  })

  test('emits relation field as optional in model interface', () => {
    // Relation fields are optional in the interface regardless of schema requiredness.
    expect(output).toContain('  posts?: Post[]')
  })

  test('emits CreateInput omitting fields with defaults', () => {
    expect(output).toContain('export interface UserCreateInput {')
    // id has a default (uuid), so it must be optional
    expect(output).toContain('  id?: string')
    expect(output).toContain('  email: string')
    expect(output).toContain('  name?: string')
    // role has a default (USER), so it must be optional
    expect(output).toContain('  role?: Role')
  })

  test('CreateInput excludes isReadOnly FK scalar', () => {
    expect(output).toContain('export interface PostCreateInput {')
    // authorId is isReadOnly → must not appear in PostCreateInput
    expect(output).not.toContain('  authorId')
  })

  test('emits UpdateInput with all fields optional', () => {
    expect(output).toContain('export interface UserUpdateInput {')
    expect(output).toContain('  id?: string')
    expect(output).toContain('  email?: string')
    expect(output).toContain('  name?: string')
    expect(output).toContain('  role?: Role')
  })

  test('emits WhereUniqueInput with id field', () => {
    expect(output).toContain('export interface UserWhereUniqueInput {')
    expect(output).toContain('  id: string')
  })

  test('WhereUniqueInput for Post uses Int id', () => {
    expect(output).toContain('export interface PostWhereUniqueInput {')
    expect(output).toContain('  id: number')
  })
})

