import { describe, expect, test } from 'vitest'

import { generateClientFile } from '../client-file'
import { testDmmf } from './fixtures'

describe('generateClientFile', () => {
  const output = generateClientFile(testDmmf)

  test('imports all model types from ./types', () => {
    expect(output).toContain("} from './types'")
    expect(output).toContain('  User,')
    expect(output).toContain('  UserCreateInput,')
    expect(output).toContain('  UserUpdateInput,')
    expect(output).toContain('  UserWhereUniqueInput,')
    expect(output).toContain('  Post,')
    expect(output).toContain('  PostCreateInput,')
  })

  test('emits a client class per model', () => {
    expect(output).toContain('export class UserClient {')
    expect(output).toContain('export class PostClient {')
  })

  test('UserClient has all five CRUD methods', () => {
    expect(output).toContain('async findMany(')
    expect(output).toContain('async findUnique(')
    expect(output).toContain('async create(')
    expect(output).toContain('async update(')
    expect(output).toContain('async delete(')
  })

  test('findMany returns the correct array type', () => {
    expect(output).toContain('Promise<User[]>')
  })

  test('findUnique returns nullable model', () => {
    expect(output).toContain('Promise<User | null>')
  })

  test('create uses POST method', () => {
    expect(output).toContain("method: 'POST'")
  })

  test('update uses PATCH method', () => {
    expect(output).toContain("method: 'PATCH'")
  })

  test('delete uses DELETE method', () => {
    expect(output).toContain("method: 'DELETE'")
  })

  test('URL slug for User is lowercased model name', () => {
    // findMany URL
    expect(output).toContain('`${this.#baseUrl}/user`')
    // findUnique / update / delete URL with id interpolation
    expect(output).toContain('`${this.#baseUrl}/user/${where.id}`')
  })

  test('URL slug for Post is lowercased model name', () => {
    expect(output).toContain('`${this.#baseUrl}/post`')
    expect(output).toContain('`${this.#baseUrl}/post/${where.id}`')
  })

  test('emits RestApiClient aggregate class', () => {
    expect(output).toContain('export class RestApiClient {')
    expect(output).toContain('readonly user: UserClient')
    expect(output).toContain('readonly post: PostClient')
  })

  test('RestApiClient constructor instantiates each model client', () => {
    expect(output).toContain('this.user = new UserClient(baseUrl)')
    expect(output).toContain('this.post = new PostClient(baseUrl)')
  })

  test('native fetch is used (no import needed for Node >=18)', () => {
    expect(output).not.toContain("import fetch")
    expect(output).toContain('await fetch(')
  })
})

